const text = $input.item.json.response || '';
const cleaned = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { score: 5, deductions: 'לא ניתן להעריך', improvement: '' };
}
return [{ json: {
  score: parsed.score || 5,
  deductions: parsed.deductions || '',
  improvement: parsed.improvement || '',
  agentName: $('Parse New Agent').first().json.name,
  chatId: $('Parse New Agent').first().json.chatId
}}];

const userMessage = $('Telegram Trigger').item.json.message.text;
const chatId = $('Telegram Trigger').item.json.message.chat.id;

let memory = [];
try {
  const items = $('Read Memory').all();
  if (items && items.length > 0) {
    const first = items[0].json;
    if (Array.isArray(first)) memory = first;
    else memory = items.map(i => i.json);
  }
} catch(e) {}

const conversationHistory = memory.slice(-20)
  .map(m => `User: ${m.task}\nעבד: ${(m.result || '').substring(0, 500)}`)
  .join('\n\n') || '';

return [{ json: { userMessage, chatId, conversationHistory } }];

// ========================================
// פרסור תוצאות מ-Yad2 API
// ========================================
const body = $input.first().json;

const listings =
  body?.data?.markers ||
  body?.data?.feed?.feed_items ||
  body?.feed?.feed_items ||
  body?.markers ||
  [];

if (!listings || listings.length === 0) {
  console.log('RAW:', JSON.stringify(body).substring(0, 600));
  return [];
}

return listings
  .filter(l => l && (l.id || l.orderId))
  .map(l => ({
    json: {
      // id חייב להיות string אחיד - זה מה שנכנס ל-dedup
      id: String(l.id || l.orderId || ''),
      price:        l.price || l.feedPrice || 0,
      rooms:        l.roomsCount || l.rooms || '?',
      floor:        l.floor !== undefined ? l.floor : '?',
