const data = $('Prepare Data').first().json;
const msg = String(data.userMessage || '');
const lower = msg.toLowerCase();
const agents = Array.isArray(data.agents) ? data.agents : [];

const hasAny = (words) => words.some(w => lower.includes(w.toLowerCase()));
const chitchatWords = ['מה המצב', 'היי', 'שלום', 'בוקר טוב', 'ערב טוב', 'תודה', 'מי אתה', 'פירוט', 'תן פירוט', 'פרט'];
const codeWords = ['code', 'python', 'javascript', 'js', 'sql', 'html', 'css', 'react', 'bug', 'debug', 'דיבאג', 'קוד', 'פונקציה', 'סקריפט', 'שגיאה'];

let action = 'create_agent';
let agent_name = null;
let decision_reason = 'לא נמצא סוכן קיים שעבר את סף ההתאמה, לכן נוצר סוכן חדש.';
let inner_thought = 'אני משווה את הבקשה מול קטלוג הסוכנים, ציונים ושימושים קודמים.';
let candidates = [];

if (!msg.trim() || hasAny(chitchatWords)) {
  action = 'chitchat';
  decision_reason = 'ההודעה נראית כמו שיחה רגילה או בקשת פירוט, לכן אין צורך בסוכן משימתי.';
  inner_thought = 'זו אינטראקציה שיחתית. אני שומר הקשר אישי ומחזיר תשובה קצרה.';
} else if (hasAny(codeWords) && agents.some(a => a.name === 'code_helper')) {
  action = 'use_agent';
  agent_name = 'code_helper';
  decision_reason = 'זוהו מילות קוד/דיבאג, ו-code_helper קיים ופעיל.';
  inner_thought = 'הבקשה טכנית. אני מעדיף סוכן קוד מוכר במקום ליצור כפילות.';
} else {
  const tokens = lower
    .replace(/[^a-z0-9א-ת_\s]/gi, ' ')
    .split(/\s+/)
    .filter(t => t.length >= 3);

  let best = null;
  let bestScore = 0;
  for (const agent of agents) {
    const haystack = [agent.name, agent.description, agent.good_for].join(' ').toLowerCase();
    let score = 0;
    for (const token of tokens) {
      if (haystack.includes(token)) score += 1;
    }
    score += Math.min(Number(agent.score_avg ?? agent.score ?? 0) || 0, 10) / 20;
    score += Math.min(Number(agent.uses ?? 0) || 0, 20) / 100;
    const item = {
      name: agent.name,
      score: Number(score.toFixed(2)),
      avg: agent.score_avg ?? agent.score ?? null,
      uses: agent.uses ?? 0,
      description: agent.description || ''
    };
    candidates.push(item);
    if (score > bestScore) {
      bestScore = score;
      best = agent;
    }
  }
  candidates = candidates.sort((a, b) => b.score - a.score).slice(0, 5);

  if (best && bestScore >= 1.3) {
    action = 'use_agent';
    agent_name = best.name;
    decision_reason = `נבחר ${best.name} כי קיבל התאמה ${bestScore.toFixed(2)} והוא הסוכן החזק ביותר למשימה הזו.`;
    inner_thought = 'יש סוכן קיים שעובר את הסף. אני משתמש בו כדי לא ליצור כפילות חלשה.';
  }
}

return [{ json: { action, agent_name, decision_reason, inner_thought, candidates, userMessage: data.userMessage, chatId: data.chatId } }];

const input = $input.item.json || {};
if (input.action) {
  return [{ json: {
    action: input.action || 'chitchat',
    agent_name: input.agent_name || null,
    decision_reason: input.decision_reason || '',
    inner_thought: input.inner_thought || '',
