parameters.jsCode:
const userMessage = $('Telegram Trigger').item.json.message.text;
const chatId = $('Telegram Trigger').item.json.message.chat.id;

let memory = [];
try {
  const items = $('Read Memory').all();
  if (items && items.length > 0) {
    const first = items[0].json;
    if (Array.isArray(first)) memory = first;
    else memory = items.map(i => i.json);
  }
} catch(e) {}

const conversationHistory = memory.slice(-20)
  .map(m => `User: ${m.task}\nעבד: ${(m.result || '').substring(0, 500)}`)
  .join('\n\n') || '';

return [{ json: { userMessage, chatId, conversationHistory } }];

const userMessage = $('Telegram Trigger').item.json.message.text || '';
const chatId = $('Telegram Trigger').item.json.message.chat.id;

let registry = [];
try {
  const items = $('Read Registry').all();
  if (items && items.length > 0) {
    const first = items[0].json;
    if (Array.isArray(first)) registry = first;
    else if (Array.isArray(first.agents)) registry = first.agents;
    else registry = items.map(i => i.json);
  }
} catch(e) {}

let memory = [];
try {
  const items = $('Read Memory').all();
  if (items && items.length > 0) {
    const first = items[0].json;
    if (Array.isArray(first)) memory = first;
    else if (Array.isArray(first.memory)) memory = first.memory;
    else memory = items.map(i => i.json);
  }
} catch(e) {}

const activeAgents = registry
  .filter(a => (a.status || 'active') === 'active')
  .sort((a, b) => {
    const scoreA = Number(a.score_avg ?? a.score ?? 0);
    const scoreB = Number(b.score_avg ?? b.score ?? 0);
    const usesA = Number(a.uses ?? 0);
    const usesB = Number(b.uses ?? 0);
    return (scoreB - scoreA) || (usesB - usesA);
  });

const agentList = activeAgents.slice(0, 8).length > 0
  ? activeAgents.slice(0, 8).map(a => `- ${a.name}: ${a.description} (good for: ${a.good_for || ''}; avg score: ${a.score_avg ?? a.score ?? 'new'}; uses: ${a.uses ?? 0})`).join('\n')
  : 'No agents yet';

const recentMemory = memory.slice(-3)
  .map(m => `[${m.agent}] ${String(m.task || '').substring(0, 120)}`)
  .join('\n') || 'None';

const conversationHistory = memory.slice(-3)
  .map(m => {
    const assistant = m.agent === 'chitchat' ? 'Assistant' : `Assistant [${m.agent}]`;
    return `User: ${String(m.task || '').substring(0, 180)}\n${assistant}: ${String(m.result || '').substring(0, 220)}`;
  })
  .join('\n\n') || '';

return [{ json: { userMessage, chatId, agents: activeAgents, agentList, recentMemory, conversationHistory } }];

const data = $('Prepare Data').first().json;
const msg = String(data.userMessage || '');
const lower = msg.toLowerCase();
const agents = Array.isArray(data.agents) ? data.agents : [];

const hasAny = (words) => words.some(w => lower.includes(w.toLowerCase()));
const chitchatWords = ['מה המצב', 'היי', 'שלום', 'בוקר טוב', 'ערב טוב', 'תודה', 'מי אתה', 'פירוט', 'תן פירוט', 'פרט'];
const codeWords = ['code', 'python', 'javascript', 'js', 'sql', 'html', 'css', 'react', 'bug', 'debug', 'דיבאג', 'קוד', 'פונקציה', 'סקריפט', 'שגיאה'];

let action = 'create_agent';
let agent_name = null;

if (!msg.trim() || hasAny(chitchatWords)) {
  action = 'chitchat';
} else if (hasAny(codeWords) && agents.some(a => a.name === 'code_helper')) {
  action = 'use_agent';
  agent_name = 'code_helper';
} else {
  const tokens = lower
    .replace(/[^a-z0-9א-ת_\s]/gi, ' ')
    .split(/\s+/)
    .filter(t => t.length >= 3);

  let best = null;
  let bestScore = 0;
  for (const agent of agents) {
    const haystack = [agent.name, agent.description, agent.good_for].join(' ').toLowerCase();
    let score = 0;
    for (const token of tokens) {
      if (haystack.includes(token)) score += 1;
    }
    score += Math.min(Number(agent.score_avg ?? agent.score ?? 0) || 0, 10) / 20;
    score += Math.min(Number(agent.uses ?? 0) || 0, 20) / 100;
    if (score > bestScore) {
      bestScore = score;
      best = agent;
    }
  }

  if (best && bestScore >= 1.3) {
    action = 'use_agent';
    agent_name = best.name;
  }
}

const decision_reason = action === 'use_agent' ? `נבחר ${agent_name} לפי התאמה, ציון ושימושים קודמים.` : (action === 'create_agent' ? 'לא נמצא סוכן מתאים מספיק, לכן נוצר סוכן חדש.' : 'זוהתה שיחה רגילה, לכן אין צורך בסוכן משימתי.');
return [{ json: { action, agent_name, decision_reason, userMessage: data.userMessage, chatId: data.chatId } }];

const input = $input.item.json || {};
if (input.action) {
  return [{ json: {
    action: input.action || 'chitchat',
    agent_name: input.agent_name || null,
    decision_reason: input.decision_reason || '',
    userMessage: input.userMessage || $('Prepare Data').first().json.userMessage,
    chatId: input.chatId || $('Prepare Data').first().json.chatId
  }}];
}

const text = input.response || '';
const cleaned = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { action: 'chitchat', agent_name: null };
}
const userMessage = $('Prepare Data').first().json.userMessage;
const chatId = $('Prepare Data').first().json.chatId;
return [{ json: {
  action: parsed.action || 'chitchat',
  agent_name: parsed.agent_name || null,
  decision_reason: parsed.decision_reason || '',
  userMessage,
  chatId
}}];

